// 'data', 'variables', 'options', and 'utils' are passed as arguments
let sources = data.series[0].fields.find(f => f.name === 'source').values.buffer || data.series[0].fields.find(f => f.name === 'source').values;
let targets = data.series[0].fields.find(f => f.name === 'target').values.buffer || data.series[0].fields.find(f => f.name === 'target').values;
let weights = data.series[0].fields.find(f => f.name === 'weight').values.buffer || data.series[0].fields.find(f => f.name === 'weight').values;
let users = data.series[0].fields.find(f => f.name === 'unique_users').values.buffer || data.series[0].fields.find(f => f.name === 'unique_users').values;

const EVENT_LABELS = {
  'user.signed_up': 'Sign Up',
  'user.profile_completed': 'Profile Setup',
  'user.logged_in': 'Login',
  'conversation.started': 'Start Conversation',
  'workspace.created': 'Create Workspace',
  'job.defined': 'Define Job',
  'session.started': 'Session Started',
  'session.completed': 'Session Completed',
  'session.failed': 'Session Failed',
  'artifact.created': 'Artifact Created',
  'gist.created': 'Gist Created'
};

const NODE_COLORS = {
  'user.signed_up': '#2ecc71',
  'user.profile_completed': '#27ae60',
  'user.logged_in': '#3498db',
  'conversation.started': '#9b59b6',
  'workspace.created': '#e67e22',
  'job.defined': '#f39c12',
  'session.started': '#1abc9c',
  'session.completed': '#16a085',
  'session.failed': '#e74c3c',
  'artifact.created': '#8e44ad',
  'gist.created': '#2980b9'
};

// Explicit node positions to fill the full diagram area
const NODE_POS = {
  'user.signed_up':        { x: 0.001, y: 0.1 },
  'user.logged_in':        { x: 0.001, y: 0.7 },
  'user.profile_completed':{ x: 0.15,  y: 0.1 },
  'conversation.started':  { x: 0.30,  y: 0.15 },
  'workspace.created':     { x: 0.30,  y: 0.75 },
  'session.started':       { x: 0.50,  y: 0.4 },
  'job.defined':           { x: 0.65,  y: 0.2 },
  'artifact.created':      { x: 0.80,  y: 0.35 },
  'gist.created':          { x: 0.80,  y: 0.8 },
  'session.completed':     { x: 0.999, y: 0.25 },
  'session.failed':        { x: 0.999, y: 0.85 }
};

let allNodesSet = new Set();
for (let i = 0; i < sources.length; i++) {
  allNodesSet.add(sources[i]);
  allNodesSet.add(targets[i]);
}
let allNodes = Array.from(allNodesSet);
let nodeIdx = {};
allNodes.forEach((n, i) => { nodeIdx[n] = i; });

let nodeLabels = allNodes.map(n => EVENT_LABELS[n] || n.replace(/\./g, ' ').replace(/_/g, ' '));
let nodeColors = allNodes.map(n => NODE_COLORS[n] || '#95a5a6');
let nodeX = allNodes.map(n => NODE_POS[n] ? NODE_POS[n].x : 0.5);
let nodeY = allNodes.map(n => NODE_POS[n] ? NODE_POS[n].y : 0.5);

let linkSources = [];
let linkTargets = [];
let linkValues = [];
let linkColors = [];
let customData = [];

for (let i = 0; i < sources.length; i++) {
  linkSources.push(nodeIdx[sources[i]]);
  linkTargets.push(nodeIdx[targets[i]]);
  linkValues.push(weights[i]);

  let hex = NODE_COLORS[sources[i]] || '#95a5a6';
  let r = parseInt(hex.slice(1,3), 16);
  let g = parseInt(hex.slice(3,5), 16);
  let b = parseInt(hex.slice(5,7), 16);
  linkColors.push('rgba(' + r + ',' + g + ',' + b + ',0.4)');

  let srcLabel = EVENT_LABELS[sources[i]] || sources[i];
  let tgtLabel = EVENT_LABELS[targets[i]] || targets[i];
  customData.push(srcLabel + ' \u2192 ' + tgtLabel + ': ' + weights[i] + ' transitions (' + users[i] + ' users)');
}

return {
  data: [{
    type: 'sankey',
    arrangement: 'fixed',
    node: {
      pad: 25,
      thickness: 30,
      line: { color: '#555', width: 0.5 },
      label: nodeLabels,
      color: nodeColors,
      x: nodeX,
      y: nodeY
    },
    link: {
      source: linkSources,
      target: linkTargets,
      value: linkValues,
      color: linkColors,
      customdata: customData,
      hovertemplate: '%{customdata}<extra></extra>'
    }
  }],
  layout: {
    font: { size: 13, color: '#ccc' },
    paper_bgcolor: 'rgba(0,0,0,0)',
    plot_bgcolor: 'rgba(0,0,0,0)',
    margin: { l: 5, r: 5, t: 5, b: 5 }
  },
  config: {
    displayModeBar: false
  }
};
